cards = []
for idx, p in enumerate(products):
    is_destaque = p['destaque'].lower() in ('sim', 'yes')
    destaque_badge = f'<span class="badge-destaque"><i class="fa-solid fa-star"></i> Destaque</span>' if is_destaque else '<span></span>'
    specs = ''
    if p.get('velocidade'):
        specs += f'<span class="card-spec"><i class="fa-solid fa-gauge-high"></i> {p["velocidade"]}</span>'
    if p.get('potencia'):
        specs += f'<span class="card-spec"><i class="fa-solid fa-bolt"></i> {p["potencia"]}</span>'
    if p.get('autonomia'):
        specs += f'<span class="card-spec"><i class="fa-solid fa-road"></i> {p["autonomia"]}</span>'
    
    card = f'''<div onclick="openProductModal({p['id']})" class="catalog-card-premium" style="animation-delay:{idx*60}ms">
    <div class="relative overflow-hidden">
        <img src="{p['imagem']}" alt="{p['nome']}" class="card-image" loading="lazy" onerror="this.src='assets/logo-desktop-motochefe-campo-grande-veiculos-eletricos.webp'">
        <div class="card-badges">
            {destaque_badge}
            <span class="badge-categoria">{p['categoria']}</span>
        </div>
    </div>
    <div class="card-content">
        <h3 class="card-title">{p['nome']}</h3>
        <p class="card-desc">{p['descricao']}</p>
        <div class="card-specs">{specs}</div>
    </div>
</div>'''
    cards.append(card)

html_grid = '\n'.join(cards)
with open('temp_cards.html', 'w', encoding='utf-8') as f:
    f.write(html_grid)
print('OK')

